CREATE TABLE `signalements` (
  `id` int NOT NULL AUTO_INCREMENT,
  `titre` varchar(200) NOT NULL,
  `description` text,
  `categorie` varchar(30) DEFAULT 'AUTRE',
  `priorite` varchar(20) DEFAULT 'NORMALE',
  `statut` varchar(20) DEFAULT 'EN_ATTENTE',
  `date_signalement` text,
  `date_resolution` text,
  `commentaire_admin` text,
  `enseignant_id` int DEFAULT NULL,
  `salle_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `enseignant_id` (`enseignant_id`),
  KEY `salle_id` (`salle_id`),
  CONSTRAINT `signalements_ibfk_1` FOREIGN KEY (`enseignant_id`) REFERENCES `utilisateurs` (`id`),
  CONSTRAINT `signalements_ibfk_2` FOREIGN KEY (`salle_id`) REFERENCES `salles` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4;

